var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_BLIND","text":{"KOREA":"대관식의 준비가 거의 끝났습니다, 예하.","JPN":"戴冠式の準備が整いました、猊下。","ENG":"The coronation preparations are almost done, Your Eminence.","TWN":"主教，加冕儀式的準備工作已接近尾聲。"},"stage":{"bg":"CHURCH","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_BLIND","text":{"KOREA":"아니, 이젠 성황이라 불러드리면 될까요?","JPN":"いいえ、これからは聖皇とお呼びした方がよろしいでしょうか。","ENG":"Forgive me. Shall I call you pope from now on?","TWN":"不，是不是應該改稱聖皇？"},"stage":{"bg":"CHURCH","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"교단의 방식을 지키거라. 대관식을 치르기 전까지 난 그저 한 사람의 신도일 뿐이니.","JPN":"教団のルールに従え。戴冠式が終わるまで、我はただ一人の信徒に過ぎない。","ENG":"Stick to the Order's doctrine. Before the coronation is complete, I am merely a follower.","TWN":"遵守教團的規矩吧。在正式加冕之前，我仍然只是一名信徒而已。"},"stage":{"bg":"CHURCH","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_BLIND","text":{"KOREA":"선대 성황께서 원정에 실패하여 선종하신 뒤로, 그 빈자리를 채운 예하이십니다.","JPN":"先代の聖王が遠征に失敗しお亡くなりになられたときから、その位置を守ってくださったのは猊下でございます。","ENG":"But after the previous pope passed away due to the failed expedition, it was you who filled that position, Your Eminence.","TWN":"前任聖皇因遠征失敗而善終後，是主教頂替了空缺的位置。"},"stage":{"bg":"CHURCH","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_BLIND","text":{"KOREA":"만민의 믿음으로 예하는 대지에 축복을 내리고, 악을 물리칠 힘을 얻으셨으니, 그들에게는 예하가 곧 신앙이자 교리인 셈이죠.","JPN":"民の信頼によって猊下は大地に祝福を与え、悪を倒せる力を手にしたのです。彼らにとって猊下は信仰であり、教理そのものです。","ENG":"With the faith of all the people, it was you who blessed the earth and gained the strength to repel evil. To them, you are their faith and doctrine, Your Eminence.","TWN":"透過人們的信仰，主教將祝福降臨於大地，並得到了戰勝邪惡的力量，對人們來說您就是信仰和教義。"},"stage":{"bg":"CHURCH","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_BLIND","text":{"KOREA":"의식은 겉치레일 뿐입니다. 이미 모두가 예하를 따르고 있으니까요.","JPN":"儀式は形式に過ぎません。既に皆が猊下に従っております。","ENG":"The coronation is just a formality. Everyone is already following you.","TWN":"儀式只是走個形式而已，大家早已真誠追隨著主教。"},"stage":{"bg":"CHURCH","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"경거망동하는 것은 좋지 않다, 네퀴티아.","JPN":"軽挙妄動するのはよくない、ネキティア。","ENG":"You would be wise to be more discreet, Nequitia.","TWN":"不可輕舉妄動，莉奎蒂亞。"},"stage":{"bg":"CHURCH","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"내가 바라는 것은 엘리시온의 번영일 뿐, 나 자신을 교리보다 위에 둘 생각은 없으니까.","JPN":"我が望むのはエリシオンの繁栄のみ、我を教理より上に置くつもりはないのだ。","ENG":"All I want is prosperity for Elysion. I have no intention of putting myself above the doctrine.","TWN":"我只希望艾利森繁榮昌盛，無意淩駕於教義之上。"},"stage":{"bg":"CHURCH","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_BLIND","text":{"KOREA":"후후, 명심하겠습니다.","JPN":"ふふ、承知いたしました。","ENG":"Fu fuu, of course.","TWN":"呵呵，我會記得的。"},"stage":{"bg":"CHURCH","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_BLIND","text":{"KOREA":"음…?","JPN":"ん……？","ENG":"Mm...?","TWN":"嗯……？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_BLIND","text":{"KOREA":"땅이 울리네요. 공기도 조금 차가워졌고요.","JPN":"地響きがします。空気も少し冷たくなっています。","ENG":"The earth is shaking. And the air is getting colder.","TWN":"地面隆隆作響，空氣也變得有些寒冷。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"네퀴티아, 길잡이와 함께 전당으로 돌아가라.","JPN":"ネキティア、先に殿堂へ戻れ。","ENG":"Nequitia, return to the palace with your guide.","TWN":"莉奎蒂亞，我會派人把你送回殿堂。"},"stage":{"bg":"BLACK","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_BLIND","text":{"KOREA":"네? 하지만 전 예하의 대관식에 함께 하고 싶은 걸요.","JPN":"はい？　ですが私は猊下の戴冠式にお伴したいのですが。","ENG":"Pardon? But I wish to attend your coronation, Your Eminence.","TWN":"什麼？但我想參加您的加冕儀式。"},"stage":{"bg":"BLACK","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_BLIND","text":{"KOREA":"제가 말실수를 한 것 때문에 그러시나요?","JPN":"私が変なことを言ったからでしょうか？","ENG":"Is it because of what I said?","TWN":"是因為我說錯話了嗎？"},"stage":{"bg":"BLACK","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"지금, 하늘의 태양이 사라졌다.","JPN":"たった今、太陽が消えた。","ENG":"The sun has just disappeared from the sky.","TWN":"太陽從天空中消失了。"},"stage":{"bg":"BLACK","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_BLIND","text":{"KOREA":"태양이… 사라졌다고요?","JPN":"太陽が...…消えたとおっしゃいましたか？","ENG":"The sun is... gone?","TWN":"太陽……消失了？"},"stage":{"bg":"BLACK","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"틀림없이 역병을 불러들인 마왕의 소행일 것이다.","JPN":"まぎれもなく疫病をばら撒いた魔王の仕業であろう。","ENG":"It must be the doing of the Demon Lord who brought forth the plague.","TWN":"這一定是帶來瘟疫的那魔王所為。"},"stage":{"bg":"BLACK","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"어서 돌아가서 네가 만든 정화의 성물을 지상으로 옮겨라.","JPN":"早く戻ってそなたが作った浄化の聖物を地上へ運べ。","ENG":"Go, now. Go and move the Holy Object of Purification you created to the ground.","TWN":"回去把你的淨化聖物搬到地上。"},"stage":{"bg":"BLACK","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그리고 너의 악단을 연주하여 성물의 빛을 밝히고 역병을 막도록.","JPN":"そしてそなたの楽団に演奏させ聖物に光を灯し、疫病を防ぐのだ。","ENG":"Also, prevent the plague by making your orchestra play to illuminate the Holy Object.","TWN":"然後和你的樂團一起演奏，點亮聖物，阻止瘟疫的傳播。"},"stage":{"bg":"BLACK","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_BLIND","text":{"KOREA":"…알겠습니다.","JPN":"……かしこまりました。","ENG":"...Yes, Your Eminence.","TWN":"……明白了。"},"stage":{"bg":"BLACK","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_BLIND","text":{"KOREA":"그럼, 대관식은 어떻게 하실 건가요?","JPN":"では、戴冠式はいかがなさいますか？","ENG":"Then, what about the coronation?","TWN":"那麼加冕儀式呢？"},"stage":{"bg":"BLACK","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"평화가 없으면 왕도 없다.","JPN":"平和がなければ王もなかろう。","ENG":"There is no king if there is no peace.","TWN":"沒有和平，就沒有王。"},"stage":{"bg":"BLACK","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"왕관을 쓰는 것은, 모든 악재를 떨쳐낸 뒤에도 늦지 않으니.","JPN":"王冠を戴くのは、すべての悪材を追い払った後からでも遅くはない。","ENG":"It will not be too late to bear the crown after removing all evil from this place.","TWN":"等一切災厄消除後再加冕也不遲。"},"stage":{"bg":"BLACK","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"내 직접 성흔 순례단을 이끌고 마왕을 꺾으리라.","JPN":"我が直に聖痕の巡礼団を率いて魔王を打ち砕く。","ENG":"I will lead the Stigmata pilgrimage and defeat the Demon Lord.","TWN":"我將親自帶領聖痕朝聖團打敗魔王。"},"stage":{"bg":"BLACK","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"추기경 에클레시아.","JPN":"枢機卿エクレシア。","ENG":"Cardinal Ecclesia.","TWN":"樞機主教艾可露西亞。"},"stage":{"bg":"BLACK","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"narration","speaker":null,"text":{"KOREA":"그녀는 엘리시온의 태양을 되찾기 위해 원정에 나섰지만, 첫번째 도전은 실패했어요.","JPN":"彼女はエリシオンの太陽を取り戻すために遠征にでましたが、最初の挑戦は失敗に終わりました。","ENG":"She left on an expedition to retrieve the sun of Elysion but failed on her first attempt.","TWN":"她為了找回艾利森的太陽的進行遠征，但在第一次遠征遭遇了失敗。"},"stage":{"bg":"BLACK","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"narration","speaker":null,"text":{"KOREA":"성흔을 가진 일흔 일곱 명의 병사를 잃었고, 그 사이에 절반이 넘는 땅이 어둠에 잠겼죠.","JPN":"聖痕を持つ兵士77人を失い、その間に土地の半分以上が闇に飲み込まれてしまいました。","ENG":"She lost 77 Stigmata soldiers, and half of the land had fallen into darkness by then.","TWN":"失去了七位聖痕士兵，並有過半的領土被黑暗侵蝕。"},"stage":{"bg":"BLACK","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"엘리시온은 오랜 침식을 겪으면서, 가진 모든 걸 하나씩 잃어갔어요.","JPN":"エリシオンは長い侵食を経て、持っていたものを一つずつ失っていったのです。","ENG":"Suffering from Corruption for what felt like eons, Elysion gradually lost everything it had.","TWN":"艾利森經歷了漫長的侵蝕並漸漸失去了一個又一個珍貴的東西。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"처음엔 태양을… 그리고 사람과 땅을… 그 뒤엔 온전했던 사계를…","JPN":"最初は太陽を……そして人と大地を……その次に四季を……","ENG":"First it was the sun... Then its people and land... And eventually, its four seasons...","TWN":"先是太陽……然後是人類和領土……然後是完整的四季……"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그렇게 빼앗긴 겨울은 역병의 상징이 되었고, 역병에 물든 땅은 검은 하늘에 눈만 내리는 영원한 불모지가 되었죠.","JPN":"そうやって奪われた冬は疫病の象徴となり、疫病に汚染された大地は黒い空に雪が降り続ける永久の不毛の地となりました。","ENG":"The winter that was taken away later became the plague's symbol. The plague-infested land turned into an eternal barren wasteland, with only snow falling from the pitch-black sky.","TWN":"被奪走的冬天成了瘟疫的象徵，遭受瘟疫侵襲的土地變成了天空漆黑一片並不停下著雪的不毛之地。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"바로 지금의 이 세계처럼.","JPN":"まさに今のこの世界のように。","ENG":"Much like what's happening to this world.","TWN":"就像我們現在的世界一樣。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"당신이… 그 엘리시온 세계의 네퀴티아란 사람이라고?","JPN":"あなたが……そのエリシオンのネキティアという人だと？","ENG":"You're... Nequitia from a world called Elysion?","TWN":"你是……那個艾利森世界的莉奎蒂亞？"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"네.","JPN":"はい。","ENG":"Yes.","TWN":"是的。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"하지만 네퀴티아가 속해 있던 그 세계는 이미 오래 전 타기리온에 의해 무너졌어요.","JPN":"しかしネキティアが住んでいたあの世界は、大昔にタギリオンによって滅びました。","ENG":"But Nequitia's world was destroyed a long time ago by Thagirion.","TWN":"但莉奎蒂亞所在的世界早已被塔基里翁摧毀。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그렇게 그림자로 전락한 뒤엔, 당신들의 관리국과 싸우기도 했었죠.","JPN":"シャドウになってしまった後は、あなたたち管理局と戦うこともありました。","ENG":"After becoming a Shadow, I also fought with the Administration here.","TWN":"變成暗影之後，還曾與你們的管理局戰鬥。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그럼 지금은?","JPN":"じゃあ今は？","ENG":"Then what about now?","TWN":"現在呢？"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그 기적이란 것 덕분에 사람이 된 당신은 이제 우리의 아군이 됐다는 건가?","JPN":"その奇跡のおかげで人になったあなたは私たちの味方ということ？","ENG":"You're telling me that, thanks to a miracle, you've changed back into a human and are now our ally?","TWN":"你是說，你因為那個奇蹟變成了人類，現在是我們的盟友？"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"저는…","JPN":"私は……","ENG":"I...","TWN":"我……"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그 질문에 그렇다고 대답할 자격은 없어요.","JPN":"その質問にはい、と答える資格はありません。","ENG":"I have no right to answer, \\"yes,\\" to your question.","TWN":"我沒有資格肯定地回答這個問題。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"하지만 저에겐 마왕 타기리온이 이 현실에 강림하는 걸 막을 책임이 있습니다.","JPN":"しかし、私には魔王タギリオンがこの現実に降臨することを防がなければいけない責任があります。","ENG":"However, I do have a responsibility to prevent the Demon Lord Thagirion from emerging in this world.","TWN":"但我有責任阻止魔王塔基里翁降臨這個世界。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그러니 부탁할게요.","JPN":"ですのでお願いします。","ENG":"So please.","TWN":"所以拜託你們。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"부디 제가 당신들을 도울 수 있도록 허락해줘요.","JPN":"私があなたたちに力添えすることを許可してください。","ENG":"Please allow me to help you all.","TWN":"請允許我給你們提供一些幫助。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"레아 양이라면 우리에게 전력이 되어줄 수 있을 것 같은데.","JPN":"レア君なら私たちの戦力になれると思うのだが。","ENG":"I believe that Leah could be of help to us.","TWN":"我認為蕾亞會是我們的一大助力。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미나 양의 의견은 어떤가?","JPN":"ミナ君の意見はどうだろう？","ENG":"Mina, what do you think?","TWN":"米娜怎麼看？"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"내 의견…?","JPN":"私の意見……？","ENG":"What do I think...?","TWN":"我……？"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"솔직히, 당신의 정체를 알고 있는 이상 쉽게 믿음을 주긴 힘들어.","JPN":"正直あなたの正体を知っている以上、簡単に信じることはできない。","ENG":"To be honest, it's hard to trust you after learning who you are.","TWN":"老實說，在已經知道你的身分的情況下，我很難百分百信任你。"},"stage":{"bg":"THRONE","bgm":"THMEA_SAD_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"내가 아는 다른 세계의 사람들은 모두 나에게 칼을 겨눈 적이었거든.","JPN":"私が知っている裏世界の住民は皆、私に刃を向けた敵だったから。","ENG":"The people I've met who came from other worlds were all enemies who tried to kill me.","TWN":"因為我認識的另一個世界的人都曾與我刀刃相向。"},"stage":{"bg":"THRONE","bgm":"THMEA_SAD_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이해해요. 전 그냥 낯선 사람도 아니고, 당신들의 세계에 속하지 않은 외부의 존재이니까요.","JPN":"わかります。私はただの人でもなく、あなたたちの世界に属していない外部の存在ですから。","ENG":"I understand. I am not just a stranger, but an outsider who doesn't belong in your world.","TWN":"我能理解。我不僅是個陌生人，還是個不屬於你們的世界的存在。"},"stage":{"bg":"THRONE","bgm":"THMEA_SAD_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그런데 말이야.","JPN":"でもさ。","ENG":"But...","TWN":"不過呢。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"한편으론 확인해보고 싶은 마음이 있어.","JPN":"一方では、確かめたい気持ちもある。","ENG":"A part of me wants to see.","TWN":"另一方面，我想親眼看看。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"당신 같은 다른 세계의 사람이 정말 우릴 위해서 싸워줄 수 있는지.","JPN":"あなたのような裏世界の住民が本当に私たちのために戦ってくれるのか。","ENG":"If people from other worlds, like yourself, can really fight for us.","TWN":"像你這樣來自另一個世界的人是否真的能為我們而戰。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"적이 아니라, 같은 목적을 바라보는 아군이 되어줄 수 있는지를 말이야.","JPN":"敵ではなく、同じ目的を持つ味方になってくれるのかを。","ENG":"If you can be an ally with a shared goal and not an enemy.","TWN":"我想確認我們是否能成為目標一致的友軍，而不是敵人。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"함께할 기회만 준다면, 증명해 보일게요.","JPN":"お伴させてもらえるのであれば、証明してみせます。","ENG":"If you give me a chance, I'll prove you right.","TWN":"如果給我機會，我會證明給你看。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"당신들의 세계와 제가 지켜야 할 사람을 위해서.","JPN":"あなたたちの世界と、私が守らなければならない人のために。","ENG":"I'll fight for this world and for the person that I must protect.","TWN":"為了你們的世界和我必須保護的人們。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};